document.addEventListener("DOMContentLoaded",function(){const t=Array.prototype.slice.call(document.querySelectorAll(".staff-block-item")),e=document.querySelectorAll(".staff-block__slider .btn-slider-main");if(e){Array.prototype.slice.call(e).forEach(function(t){t.style.top="calc("+getComputedStyle(t).top+" - 250px"})}function o(){t.forEach(function(t){t.style.height="auto"}),t.forEach(function(t){t.style.height=t.offsetHeight+"px"})}o(),window.addEventListener("resize",function(){o()})});